import json
import re
from pathlib import Path

LATIN = re.compile(r"[A-Za-z]{2,}")


def H(*codes: int) -> str:
    return "".join(chr(c) for c in codes)


def q(*parts: str) -> str:
    s = "".join(parts)
    hits = LATIN.findall(s)
    if hits:
        raise ValueError(f"latin {hits} in {s[:60]!r}")
    return s


